python -c "
import pathlib, re, sys
fail = []
for py in pathlib.Path('.').glob('*.py'):
    src = py.read_text(encoding='utf-8')
    for ln, line in enumerate(src.splitlines(), 1):
        if re.search(r'boto3\.(client|resource)\(', line):
            if 'region_name' not in line and 'Session' not in line:
                if not line.strip().startswith('#'):
                    fail.append(f'{py.name}:{ln}: {line.strip()[:80]}')
if fail:
    print('[WARN] boto3 client without explicit region_name:')
    [print(f'  {f}') for f in fail]
    sys.exit(1)
else:
    print('[OK] All boto3 clients have explicit region_name')
"
